// To use any npm package, just import it
import { type DeriveActionInstance, type ActionRunOptions, type RunReturn, defineAction } from "@process.co/element-types";
import { z } from "zod";
//import axios from "axios";

// Define the action
const customCodeNodejsAction = defineAction({

  key: "process-internal-custom-code-nodejs",
  name: "Custom Code Node.js",
  description: "Run custom code in a Node.js environment",
  version: "0.0.1",
  type: "action",
  noAuth: true, // Set this to true if you do not want to force the user to authenticate the action.
  returns: "NodejsResponse",
  icon: { type: "image", icon: 'https://res.cloudinary.com/process-co/image/upload/v1760728122/nodejsHex.svg' },
  props: {

    //**
    // This is an example of a property that can be edited by the user.
    // If can be removed if you do not need it.
    //  */
    message: {
      type: "string",
      label: "Message",
      description: "The message to export",
    },

    //**
    // This is an example of a property defined using zod.
    // If you do not need it, it can be removed.
    //  */
    user: {
      type: z.object({
        name: z.string(),
        email: z.email(),
        age: z.number(),
      }),
      label: "User",
      description: "The user to export",
    },


  },

  //**
  // This is the main function that will be executed when the action is run.
  // It will export the message and user properties to the parent process.
  //  */
  run: async function ({ $ }: ActionRunOptions) {

    $.export("message", this.message);
    $.export("user", this.user);

    return {
      success: true,
      message: "Custom Code Case 2",
    };

  },
});

// Derive types from the implementation
export type NodejsAction = typeof customCodeNodejsAction;
export type NodejsResponse = RunReturn<NodejsAction>;
export type NodejsActionInstance = DeriveActionInstance<NodejsAction>;

export default customCodeNodejsAction;
